#include <stdlib.h>
#include <string.h>
#include <stdio.h>
#include <math.h>

// Helper function to count '0's and '1's in a substring
void count_bits(const char* s, int start, int end, int* zeros, int* ones) {
    *zeros = 0;
    *ones = 0;
    for (int i = start; i <= end; ++i) {
        if (s[i] == '0') {
            (*zeros)++;
        } else {
            (*ones)++;
        }
    }
}

// Helper function to check if a substring is balanced
int is_balanced(const char* s, int start, int end) {
    if (start > end) return 0;
    int zeros, ones;
    count_bits(s, start, end, &zeros, &ones);
    return zeros == ones;
}

// Function to solve the problem
int64 solve(char* s) {
    int n = strlen(s);
    int64 max_len = 0;

    // Case 0: No swap
    for (int i = 0; i < n; ++i) {
        for (int j = i; j < n; ++j) {
            if (is_balanced(s, i, j)) {
                int64 current_len = (int64)(j - i + 1);
                if (current_len > max_len) {
                    max_len = current_len;
                }
            }
        }
    }

    // Case 1: One swap
    // Iterate over all pairs of indices (i, j) to swap s[i] and s[j]
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            // Create a temporary copy of the string to perform the swap
            char* temp_s = (char*)malloc(n + 1);
            strcpy(temp_s, s);

            // Perform the swap
            char temp_char = temp_s[i];
            temp_s[i] = temp_s[j];
            temp_s[j] = temp_char;
            temp_s[i] = temp_char; // Correct assignment after swap
            temp_s[j] = s[i]; // Correct assignment after swap

            // Corrected swap logic (more robust)
            char temp_val = temp_s[i];
            temp_s[i] = temp_s[j];
            temp_s[j] = temp_val;


            // Check all substrings in the modified string
            for (int start = 0; start < n; ++start) {
                for (int end = start; end < n; ++end) {
                    if (is_balanced(temp_s, start, end)) {
                        int64 current_len = (int64)(end - start + 1);
                        if (current_len > max_len) {
                            max_len = current_len;
                        }
                    }
                }
            }
            free(temp_s);
        }
    }

    return max_len;
}
