/**
 * @brief 解决最大平衡子串长度问题。
 * 
 * 允许最多一次交换任意两个字符，然后找到一个平衡子串的最大长度。
 * 平衡子串的特点是其中 '0' 和 '1' 的数量相等。
 * 
 * @param s 仅由 '0' 和 '1' 组成的二进制字符串。
 * @return int64 最大平衡子串的长度。
 */
long long solve(std::string s) {
    int n = s.length();
    if (n == 0) return 0;

    // 统计原始的 '0' 和 '1' 的数量
    int count0 = 0;
    int count1 = 0;
    for (char c : s) {
        if (c == '0') count0++;
        else count1++;
    }

    // 最大长度的初始值，至少可以是 0 (空子串)
    long long max_len = 0;

    // --------------------------------------------------------------------------
    // 场景 1: 不进行任何交换
    // --------------------------------------------------------------------------
    // 寻找原始字符串 s 中的最长平衡子串
    // 使用前缀和 (balance: count0 - count1)
    std::vector<int> prefix_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        int val = (s[i] == '0') ? 1 : -1;
        prefix_balance[i + 1] = prefix_balance[i] + val;
    }

    // 记录每个前缀和第一次出现的位置
    std::vector<int> first_occurrence(n + 1, -1);
    first_occurrence[0] = 0;
    for (int i = 1; i <= n; ++i) {
        if (first_occurrence[prefix_balance[i]] == -1) {
            first_occurrence[prefix_balance[i]] = i;
        }
    }

    // 遍历所有前缀和，如果出现过相同的值，则中间的子串是平衡的
    for (int j = 1; j <= n; ++j) {
        int balance = prefix_balance[j];
        if (first_occurrence[balance] != -1) {
            int i = first_occurrence[balance];
            // 子串 s[i...j-1] 的长度是 j - i
            max_len = std::max(max_len, (long long)(j - i));
