#include <algorithm>

// Helper function to find the maximum length of a balanced substring in a given string
int max_balanced_substring(const char* s) {
    int n = strlen(s);
    if (n == 0) return 0;

    // prefix_sum[i] stores the count of '1's minus count of '0's in s[0...i-1]
    // We use an array of size n+1 for prefix sums, where prefix_sum[0] = 0.
    int* prefix_sum = (int*)calloc(n + 1, sizeof(int));
    for (int i = 0; i < n; ++i) {
        int value = (s[i] == '1') ? 1 : -1;
        prefix_sum[i + 1] = prefix_sum[i] + value;
    }

    // Map to store the first index where a particular prefix sum occurs
    // Key: prefix sum value, Value: index i such that prefix_sum[i] = key
    // Since the sum ranges from -N to N, we use an offset to map to a non-negative index.
    // The maximum possible sum is N, minimum is -N. Total range size is 2N+1.
    // Offset = N. Index = sum + N.
    int offset = n;
    // Size needed: 2*N + 1
    int* first_occurrence = (int*)malloc((2 * n + 1) * sizeof(int));
    for (int i = 0; i <= 2 * n; ++i) {
        first_occurrence[i] = -1; // -1 indicates not seen yet
    }

    int max_len = 0;

    for (int i = 0; i <= n; ++i) {
        int sum = prefix_sum[i];
        int mapped_sum = sum + offset;

        if (first_occurrence[mapped_sum] == -1) {
            // First time seeing this sum, record the index i
            first_occurrence[mapped_sum] = i;
        } else {
            // This sum was seen before at index j = first_occurrence[mapped_sum]
            int j = first_occurrence[mapped_sum];
            // The substring s[j...i-1] has a balanced count (sum is 0 for the difference)
            // Length is i - j
            max_len = std::max(max_len, i - j);
        }
    }

    free(prefix_sum);
    free(first_occurrence);
    return max_len;
}

// Function to perform one swap and calculate the result
