    temp = s_copy[i];
    s_copy[i] = s_copy[j];
    s_copy[j] = temp;


    // The actual swap logic in C:
    char* original_s = (char*)malloc(n + 1);
    strcpy(original_s, s);
    char* swapped_s = (char*)malloc(n + 1);
    strcpy(swapped_s, s);

